create table if not exists public.decision_revisions(id uuid primary key default gen_random_uuid(),application_id uuid not null references public.applications,decision public.application_status not null,internal_reason text not null,applicant_explanation text,decided_by uuid not null references public.profiles,confirmed_at timestamptz not null,superseded_by uuid not null references public.profiles,superseded_at timestamptz not null default now(),correction_reason text not null);
alter table public.decision_revisions enable row level security;
create policy "decision_revisions_admin_read" on public.decision_revisions for select to authenticated using(public.has_role('program_admin') or public.has_role('super_admin'));
create or replace function public.withdraw_application(p_application_id uuid,p_reason text) returns void language plpgsql security definer set search_path=public as $$ declare caller uuid:=auth.uid();old_status public.application_status;begin if caller is null then raise exception 'Please sign in again.';end if;select status into old_status from public.applications where id=p_application_id and applicant_id=caller for update;if old_status is null or old_status not in('draft','applied','review_by_admin','additional_information_needed') then raise exception 'This application cannot be withdrawn online.';end if;update public.applications set status='withdrawn',updated_at=now() where id=p_application_id;insert into public.status_history(application_id,previous_status,new_status,actor_id,reason,applicant_note) values(p_application_id,old_status,'withdrawn',caller,coalesce(nullif(trim(p_reason),''),'Applicant requested withdrawal.'),'You withdrew this application. Contact EFF if you need help.');insert into public.audit_events(actor_id,action,target_type,target_id,metadata_safe) values(caller,'application_withdrawn','application',p_application_id::text,jsonb_build_object('from',old_status));end $$;
revoke all on function public.withdraw_application(uuid,text) from public;grant execute on function public.withdraw_application(uuid,text) to authenticated;
create or replace function public.correct_application_status(p_application_id uuid,p_new_status public.application_status,p_reason text,p_applicant_note text default null) returns void language plpgsql security definer set search_path=public as $$ declare actor uuid:=auth.uid();old_status public.application_status;d public.decisions;begin if actor is null or not (public.has_role('program_admin') or public.has_role('super_admin')) or nullif(trim(p_reason),'') is null then raise exception 'An authorized administrator and correction reason are required.';end if;select status into old_status from public.applications where id=p_application_id for update;if old_status is null or old_status='archived' or p_new_status='draft' or old_status=p_new_status then raise exception 'That correction is not permitted.';end if;if old_status in('approved','denied') and p_new_status not in('approved','denied') then select * into d from public.decisions where application_id=p_application_id;if d.id is not null then insert into public.decision_revisions(application_id,decision,internal_reason,applicant_explanation,decided_by,confirmed_at,superseded_by,correction_reason) values(d.application_id,d.decision,d.internal_reason,d.applicant_explanation,d.decided_by,d.confirmed_at,actor,trim(p_reason));delete from public.decisions where id=d.id;end if;end if;update public.applications set status=p_new_status,updated_at=now() where id=p_application_id;insert into public.status_history(application_id,previous_status,new_status,actor_id,reason,applicant_note) values(p_application_id,old_status,p_new_status,actor,'CORRECTION: '||trim(p_reason),nullif(trim(p_applicant_note),''));insert into public.audit_events(actor_id,action,target_type,target_id,metadata_safe) values(actor,'application_status_corrected','application',p_application_id::text,jsonb_build_object('from',old_status,'to',p_new_status,'reason',trim(p_reason)));end $$;
revoke all on function public.correct_application_status(uuid,public.application_status,text,text) from public;grant execute on function public.correct_application_status(uuid,public.application_status,text,text) to authenticated;
